module top_module(
    input in1,
    input in2,
    input in3,
    input clk,
    input reset,
    output out1,
    output out2
);reg invalid_out1;
    reg out2_reg;

    always @(posedge clk) begin
        if (reset) begin
            invalid_out1 <= 1'b0;
            out2_reg <= 1'b0;
        end else begin
            invalid_out1 <= in1 ^ in2;
            out2_reg <= in2 & in3;
        end
    end

    assign out1 = invalid_out1;
    assign out2 = out2_reg;

endmodule
